import os
import json

# Let's check all directories and files recursively
def find_files(directory='.', max_depth=3, current_depth=0):
    if current_depth > max_depth:
        return

    try:
        for item in os.listdir(directory):
            item_path = os.path.join(directory, item)
            if os.path.isfile(item_path):
                print(f"File: {item_path}")
                if item.endswith('.jsonld'):
                    print(f"Found JSONLD file: {item_path}")
                    try:
                        with open(item_path, 'r', encoding='utf-8') as f:
                            content = f.read()
                        print(f"Content preview: {content[:500]}")
                        return item_path
                    except Exception as e:
                        print(f"Error reading {item_path}: {e}")
            elif os.path.isdir(item_path) and not item.startswith('.'):
                print(f"Directory: {item_path}")
                result = find_files(item_path, max_depth, current_depth + 1)
                if result:
                    return result
    except PermissionError:
        pass

    return None

